import os
from pathlib import Path

SANDBOX_BASE = Path(os.environ.get("AGENT_SANDBOX", "/workspace")).resolve()

ALLOWED_READ_EXTS = {".txt", ".csv", ".json", ".md", ".yaml", ".yml", ".log", ".py"}
ALLOWED_WRITE_EXTS = {".txt", ".csv", ".json", ".md"}

def _safe_path(user_path: str, write: bool = False) -> tuple[Path, dict | None]:
    """Return (resolved_path, None) or (None, error_dict)."""
    try:
        resolved = (SANDBOX_BASE / user_path).resolve()
    except Exception:
        return None, {"error": "VALIDATION_ERROR",
                      "message": f"Invalid path: {user_path!r}", "retryable": False}
    # Block path traversal
    try:
        resolved.relative_to(SANDBOX_BASE)
    except ValueError:
        return None, {"error": "PERMISSION_DENIED",
                      "message": f"Path {user_path!r} escapes the sandbox.", "retryable": False}
    # Block disallowed extensions
    allowed = ALLOWED_WRITE_EXTS if write else ALLOWED_READ_EXTS
    if resolved.suffix.lower() not in allowed:
        return None, {"error": "PERMISSION_DENIED",
                      "message": f"File type {resolved.suffix!r} is not permitted.",
                      "retryable": False}
    return resolved, None

READ_FILE_TOOL = {
    "name": "read_file",
    "description": (
        "Read the text content of a file inside the workspace. "
        "Returns up to 8000 characters. For larger files, use start_line to read from a specific offset. "
        "Supported types: .txt, .csv, .json, .md, .yaml, .yml, .log, .py."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {"type": "string", "description": "Relative path inside the workspace, e.g. 'data/report.csv'."},
            "start_line": {"type": "integer", "minimum": 1,
                           "description": "First line to return (1-indexed). Default: 1."},
            "max_lines": {"type": "integer", "minimum": 1, "maximum": 500,
                          "description": "Maximum lines to return. Default: 200."}
        },
        "required": ["path"]
    }
}

MAX_CHARS = 8000

def read_file(path: str, start_line: int = 1, max_lines: int = 200) -> dict:
    resolved, err = _safe_path(path, write=False)
    if err:
        return err
    if not resolved.exists():
        return {"error": "NOT_FOUND", "message": f"File {path!r} does not exist.", "retryable": False}
    if not resolved.is_file():
        return {"error": "VALIDATION_ERROR", "message": f"{path!r} is a directory, not a file.", "retryable": False}
    try:
        lines = resolved.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc), "retryable": True}
    total_lines = len(lines)
    start = max(0, start_line - 1)
    chunk = lines[start : start + max_lines]
    text = "\n".join(chunk)
    truncated_by_lines = len(chunk) < (total_lines - start)
    truncated_by_chars = len(text) > MAX_CHARS
    return {
        "path": path,
        "content": text[:MAX_CHARS],
        "total_lines": total_lines,
        "returned_lines": len(chunk),
        "start_line": start_line,
        "truncated": truncated_by_lines or truncated_by_chars,
    }

LIST_DIR_TOOL = {
    "name": "list_directory",
    "description": "List files and subdirectories inside a workspace directory.",
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {"type": "string",
                     "description": "Relative path to a directory. Use '.' for the workspace root."},
        },
        "required": ["path"]
    }
}

def list_directory(path: str) -> dict:
    try:
        resolved = (SANDBOX_BASE / path).resolve()
        resolved.relative_to(SANDBOX_BASE)
    except (ValueError, Exception):
        return {"error": "PERMISSION_DENIED", "message": f"Path {path!r} escapes the sandbox.", "retryable": False}
    if not resolved.exists():
        return {"error": "NOT_FOUND", "message": f"Directory {path!r} does not exist.", "retryable": False}
    if not resolved.is_dir():
        return {"error": "VALIDATION_ERROR", "message": f"{path!r} is a file, not a directory.", "retryable": False}
    entries = []
    for item in sorted(resolved.iterdir()):
        entries.append({
            "name": item.name,
            "type": "directory" if item.is_dir() else "file",
            "size_bytes": item.stat().st_size if item.is_file() else None,
            "extension": item.suffix.lower() if item.is_file() else None,
        })
    return {"path": path, "entries": entries[:100], "count": len(entries),
            "truncated": len(entries) > 100}

WRITE_FILE_TOOL = {
    "name": "write_file",
    "description": (
        "Write text content to a file in the workspace. "
        "Creates the file if it does not exist. "
        "Set overwrite=true to replace an existing file. "
        "Supported types: .txt, .csv, .json, .md."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {"type": "string"},
            "content": {"type": "string"},
            "overwrite": {"type": "boolean",
                          "description": "Set to true to replace an existing file. Default: false."}
        },
        "required": ["path", "content"]
    }
}

def write_file(path: str, content: str, overwrite: bool = False) -> dict:
    resolved, err = _safe_path(path, write=True)
    if err:
        return err
    if resolved.exists() and not overwrite:
        return {
            "error": "CONFLICT",
            "message": f"File {path!r} already exists. Set overwrite=true to replace it.",
            "retryable": False,
            "details": {"existing_size_bytes": resolved.stat().st_size},
        }
    try:
        resolved.parent.mkdir(parents=True, exist_ok=True)
        resolved.write_text(content, encoding="utf-8")
    except OSError as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc), "retryable": True}
    return {
        "path": path,
        "written_bytes": len(content.encode("utf-8")),
        "created": True,
    }

def append_to_file(path: str, content: str) -> dict:
    resolved, err = _safe_path(path, write=True)
    if err:
        return err
    if not resolved.exists():
        return {
            "error": "NOT_FOUND",
            "message": f"{path!r} does not exist. Use write_file to create it first.",
            "retryable": False,
        }
    try:
        with resolved.open("a", encoding="utf-8") as f:
            f.write(content)
    except OSError as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc), "retryable": True}
    return {
        "path": path,
        "appended_bytes": len(content.encode("utf-8")),
        "total_size_bytes": resolved.stat().st_size,
    }

def search_in_file(path: str, pattern: str, max_matches: int = 20) -> dict:
    import re
    resolved, err = _safe_path(path, write=False)
    if err:
        return err
    if not resolved.exists():
        return {"error": "NOT_FOUND", "message": f"{path!r} does not exist.", "retryable": False}
    try:
        lines = resolved.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc), "retryable": True}
    try:
        rx = re.compile(pattern, re.IGNORECASE)
    except re.error as exc:
        return {"error": "VALIDATION_ERROR",
                "message": f"Invalid regex pattern: {exc}", "retryable": False}
    matches = [
        {"line_number": i + 1, "text": line.strip()}
        for i, line in enumerate(lines)
        if rx.search(line)
    ]
    return {
        "path": path,
        "pattern": pattern,
        "matches": matches[:max_matches],
        "total_matches": len(matches),
        "truncated": len(matches) > max_matches,
    }

def stat_file(path: str) -> dict:
    resolved, err = _safe_path(path, write=False)
    if err:
        return err
    if not resolved.exists():
        return {"error": "NOT_FOUND", "message": f"{path!r} does not exist.", "retryable": False}
    stat = resolved.stat()
    line_count = None
    if resolved.suffix.lower() in {".txt", ".csv", ".md", ".log", ".py", ".json"}:
        try:
            text = resolved.read_text(encoding="utf-8", errors="replace")
            line_count = text.count("\n") + 1
        except OSError:
            pass
    return {
        "path": path,
        "size_bytes": stat.st_size,
        "size_kb": round(stat.st_size / 1024, 1),
        "extension": resolved.suffix.lower(),
        "line_count": line_count,
        "readable_without_truncation": stat.st_size < 8000,
    }
